CREATE TABLE `menu_categories` (
	`id` varchar(36) NOT NULL,
	`menu_id` varchar(36) NOT NULL,
	`name` varchar(255) NOT NULL,
	`order` int NOT NULL DEFAULT 0,
	`created_at` bigint NOT NULL,
	CONSTRAINT `menu_categories_id` PRIMARY KEY(`id`)
);

CREATE TABLE `menu_items` (
	`id` varchar(36) NOT NULL,
	`category_id` varchar(36) NOT NULL,
	`name` varchar(255) NOT NULL,
	`price` int NOT NULL,
	`order` int NOT NULL DEFAULT 0,
	`created_at` bigint NOT NULL,
	CONSTRAINT `menu_items_id` PRIMARY KEY(`id`)
);

CREATE TABLE `menus` (
	`id` varchar(36) NOT NULL,
	`name` varchar(255) NOT NULL,
	`description` text,
	`is_active` boolean NOT NULL DEFAULT false,
	`created_at` bigint NOT NULL,
	`updated_at` bigint NOT NULL,
	CONSTRAINT `menus_id` PRIMARY KEY(`id`)
);

CREATE INDEX `menu_id_idx` ON `menu_categories` (`menu_id`);
CREATE INDEX `category_id_idx` ON `menu_items` (`category_id`);
CREATE INDEX `is_active_idx` ON `menus` (`is_active`);

